// =====================================================
// ETAPE 2: VALIDATION & EXTRACTION
// Valide les donnees et extrait les infos cles
// =====================================================

const webhook = $input.first().json;
const body = webhook.body || {};

// Extraction des donnees
const email = (body.email || '').trim().toLowerCase();
const message = (body.message || '').trim();
const sessionId = body.session_id || null;
const conversationHistory = body.conversation_history || [];

// Validation email
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const isValidEmail = emailRegex.test(email);

if (!isValidEmail || !message) {
  return [{
    json: {
      error: true,
      errorMessage: !isValidEmail ? 'Email invalide' : 'Message vide',
      shouldRespond: true
    }
  }];
}

// Detection d'intent simple (pour routage)
const messageLower = message.toLowerCase();
let detectedIntent = 'general';
let urgency = 'normal';

// Detection intent
if (messageLower.includes('cass') && messageLower.includes('livr')) {
  detectedIntent = 'casse_transport';
  urgency = 'high';
} else if (messageLower.includes('cass') && messageLower.includes('mont')) {
  detectedIntent = 'casse_montage';
  urgency = 'high';
} else if (messageLower.includes('cass')) {
  detectedIntent = 'casse_general';
  urgency = 'high';
} else if (messageLower.includes('dimension') || messageLower.includes('taille') || messageLower.includes('mesure')) {
  detectedIntent = 'dimensions';
} else if (messageLower.includes('suivi') || messageLower.includes('commande') || messageLower.includes('livraison')) {
  detectedIntent = 'suivi';
} else if (messageLower.includes('rembours') || messageLower.includes('avoir')) {
  detectedIntent = 'remboursement';
} else if (messageLower.includes('assurance')) {
  detectedIntent = 'assurance';
}

// Extraction numero de commande si present
const commandeMatch = message.match(/\b(\d{5,6})\b/);
const commandeId = commandeMatch ? commandeMatch[1] : null;

// Compter les messages pour savoir si on doit resumer
const messageCount = conversationHistory.length;
const shouldSummarize = messageCount >= 10;

return [{
  json: {
    error: false,
    email,
    message,
    sessionId,
    conversationHistory,
    detectedIntent,
    urgency,
    commandeId,
    messageCount,
    shouldSummarize,
    timestamp: new Date().toISOString()
  }
}];

