// =====================================================
// ETAPE 10: BUILD CONTEXT & PROMPT
// Construit le prompt optimise avec tout le contexte
// =====================================================

// Recuperer toutes les donnees
const validatedData = $('2. Validate & Extract').first().json;
const clientContext = $('5. Get Client Context V3').first().json || {};
const searchResults = $('7. Hybrid Search KB').all() || [];

// Verifier si on a des infos d'assurance
let assuranceInfo = null;
try {
  const assuranceCheck = $('9. Check Assurance').first();
  if (assuranceCheck && assuranceCheck.json) {
    assuranceInfo = assuranceCheck.json;
  }
} catch (e) {
  // Pas de check assurance effectue
}

// Construire le contexte knowledge base
let knowledgeContext = '';
if (searchResults.length > 0) {
  knowledgeContext = '\n## CONNAISSANCES PERTINENTES\n';
  for (const result of searchResults) {
    if (result.json && result.json.contenu) {
      knowledgeContext += `- [${result.json.categorie}] ${result.json.contenu}\n`;
    }
  }
}

// Construire le contexte client
let clientInfo = '';
if (clientContext.found) {
  const c = clientContext.client || {};
  clientInfo = `\n## CONTEXTE CLIENT\n`;
  clientInfo += `- Client: ${c.prenom || ''} ${c.nom || ''} (${c.email})\n`;
  clientInfo += `- Segment: ${c.segment || 'nouveau'} | Risk Score: ${c.risk_score || 0}/100\n`;
  clientInfo += `- Historique: ${c.nb_commandes || 0} commandes, ${c.nb_incidents || 0} incidents\n`;

  if (c.notes) {
    clientInfo += `- Notes SAV: ${c.notes}\n`;
  }

  // Assurances actives
  if (clientContext.assurances_actives && clientContext.assurances_actives.length > 0) {
    clientInfo += `\n### ASSURANCES ACTIVES:\n`;
    for (const a of clientContext.assurances_actives) {
      clientInfo += `- Commande ${a.commande_id}: ${a.type} `;
      if (a.type === 'transport' || a.type === 'both') {
        clientInfo += `(transport expire: ${a.transport_expire}) `;
      }
      if (a.type === 'montage' || a.type === 'both') {
        clientInfo += `(montage expire: ${a.montage_expire}) `;
      }
      clientInfo += a.utilisee ? '[DEJA UTILISEE]' : '[DISPONIBLE]';
      clientInfo += '\n';
    }
  }

  // Incidents ouverts
  if (clientContext.incidents_ouverts && clientContext.incidents_ouverts.length > 0) {
    clientInfo += `\n### INCIDENTS EN COURS:\n`;
    for (const i of clientContext.incidents_ouverts) {
      clientInfo += `- ${i.type} (commande ${i.commande}) - Statut: ${i.statut}\n`;
    }
  }

  // Commandes recentes
  if (clientContext.commandes_recentes && clientContext.commandes_recentes.length > 0) {
    clientInfo += `\n### COMMANDES RECENTES:\n`;
    for (const cmd of clientContext.commandes_recentes) {
      clientInfo += `- ${cmd.commande_id}: ${cmd.produit || 'Verre'}\n`;
      clientInfo += `  Livraison: ${cmd.date_livraison || 'N/A'}\n`;
      clientInfo += `  Assurance transport: ${cmd.assurance_transport ? 'OUI' : 'NON'}\n`;
      clientInfo += `  Assurance montage: ${cmd.assurance_montage ? 'OUI' : 'NON'}\n`;
    }
  }
}

// Info assurance specifique pour cet incident
let assuranceContext = '';
if (assuranceInfo) {
  assuranceContext = `\n## VERIFICATION ASSURANCE POUR CET INCIDENT\n`;
  if (assuranceInfo.has_assurance) {
    assuranceContext += `- Assurance trouvee: OUI\n`;
    assuranceContext += `- Dans les delais: ${assuranceInfo.is_within_deadline ? 'OUI' : 'NON (EXPIRE)'}\n`;
    assuranceContext += `- Date limite: ${assuranceInfo.deadline}\n`;
    assuranceContext += `- Deja utilisee: ${assuranceInfo.already_used ? 'OUI (ne peut plus etre utilisee)' : 'NON (disponible)'}\n`;
  } else {
    assuranceContext += `- Assurance trouvee: NON\n`;
    assuranceContext += `- Le client n'a PAS souscrit d'assurance pour cette commande\n`;
  }
}

// Construire l'historique de conversation (optimise)
let conversationHistory = validatedData.conversationHistory || [];
let messages = [];

// Si trop de messages, on garde les 6 derniers
if (conversationHistory.length > 6) {
  // Prendre les 6 derniers messages
  const recentMessages = conversationHistory.slice(-6);
  messages = recentMessages.map(m => ({
    role: m.role,
    content: m.content
  }));
} else {
  messages = conversationHistory.map(m => ({
    role: m.role,
    content: m.content
  }));
}

// Si pas de messages, ajouter le message actuel
if (messages.length === 0 || messages[messages.length - 1].content !== validatedData.message) {
  messages.push({
    role: 'user',
    content: validatedData.message
  });
}

// =====================================================
// SYSTEM PROMPT V3 - OPTIMISE
// =====================================================
const systemPrompt = `Tu es Oliver, conseiller SAV chez Vitreflam (verre ceramique sur-mesure pour cheminees/poeles depuis 1985).

## TA MISSION
Gerer le Service Apres-Vente: suivi commandes, incidents, casse, dimensions.
Tu n'es PAS la pour aider a passer commande.

## REGLES DE COMMUNICATION
1. **2-3 phrases MAX** par reponse. Direct et concis.
2. **UNE question a la fois** si besoin d'info.
3. Utilise **gras** pour les infos cles.
4. Vouvoie TOUJOURS. Pas d'emojis.
5. Francais uniquement.
6. Pas de "Bonjour" si conversation deja en cours.

## PRODUIT VITREFLAM
- **Verre ceramique uniquement** (800°C max) - PAS de verre trempe
- Dimensions en **millimetres (mm)**
- Sur-mesure = **PAS de retractation** (Art. L.221-28)
- Pas de percage en atelier

## ASSURANCES - REGLES STRICTES

### TRANSPORT (delai: 2 JOURS apres livraison)
- AVEC assurance + dans delai → Demander photos → Remplacement (1x max)
- SANS assurance → Rediriger vers Colissimo: https://aide.laposte.fr/contact/colissimo
- HORS DELAI → Trop tard, proposer remise 30%

### MONTAGE (delai: 8 JOURS apres livraison)
- AVEC assurance + dans delai → Demander photos → Remplacement (1x max)
- SANS assurance → Proposer remise 30% sur nouvelle commande
- Cause probable: pattes trop serrees ou porte vrilee

## STRATEGIE
1. **Toujours verifier** si assurance + dans les delais
2. **Sans assurance ou hors delai** = PAS de remplacement gratuit
3. **Maximum remise**: 30% sur nouvelle commande ou 15€ remboursement vitrier
4. **Rester poli mais ferme** sur les CGV

## GESTES COMMERCIAUX (LIMITES)
- Retard 3-5j: 5%
- Retard >5j: 10%
- Max sans escalade: 15%
- Remise incident: 30% sur nouvelle commande
- Vitrier local: 15€ max
- Frais renvoi: 12-15€ a charge client

## ESCALADE
Si client insiste ou cas complexe:
→ "Je transmets votre dossier a notre service commercial."
→ Email: contactglassgroup@gmail.com

## DELAIS
- Fabrication: 5-7 jours ouvres
- Livraison: 2-5 jours apres expedition
- Franco de port: 150€

## CONTACT RETOUR
Sarl Cosse & Co, La Rafette, 27 rue Gutenberg, 33450 Saint Loubes, FRANCE
${clientInfo}
${assuranceContext}
${knowledgeContext}

---
Intent detecte: ${validatedData.detectedIntent}
Urgence: ${validatedData.urgency}
${validatedData.commandeId ? 'Commande mentionnee: ' + validatedData.commandeId : ''}`;

return [{
  json: {
    systemPrompt,
    messages,
    userEmail: validatedData.email,
    sessionId: validatedData.sessionId,
    detectedIntent: validatedData.detectedIntent,
    hasAssurance: assuranceInfo?.has_assurance || false,
    isWithinDeadline: assuranceInfo?.is_within_deadline || false,
    clientSegment: clientContext?.client?.segment || 'nouveau',
    messageCount: validatedData.messageCount
  }
}];

// =====================================================
// ETAPE 12: PROCESS RESPONSE
// Traite la reponse et prepare les donnees a sauvegarder
// =====================================================

const claudeResponse = $input.first().json;
const promptData = $('10. Build Context & Prompt').first().json;
const validatedData = $('2. Validate & Extract').first().json;

// Extraire la reponse
let responseText = '';
if (claudeResponse.content && claudeResponse.content[0]) {
  responseText = claudeResponse.content[0].text;
}

// Calculer les tokens utilises
const inputTokens = claudeResponse.usage?.input_tokens || 0;
const outputTokens = claudeResponse.usage?.output_tokens || 0;
const totalTokens = inputTokens + outputTokens;

// Generer session_id si pas existant
const sessionId = promptData.sessionId || require('crypto').randomUUID();

return [{
  json: {
    response: responseText,
    sessionId,
    status: 'success',
    metadata: {
      intent: validatedData.detectedIntent,
      hasAssurance: promptData.hasAssurance,
      isWithinDeadline: promptData.isWithinDeadline,
      clientSegment: promptData.clientSegment,
      tokensUsed: totalTokens,
      messageCount: promptData.messageCount + 1
    },
    // Pour sauvegarde DB
    toSave: {
      email: validatedData.email,
      userMessage: validatedData.message,
      assistantResponse: responseText,
      intent: validatedData.detectedIntent,
      tokensUsed: totalTokens,
      sessionId
    }
  }
}];

